codeTemplate:
idle-states {
    entry-method = "psci";

    cpu-sleep {
        compatible = "arm,idle-state";
        ___ = <500>;
        exit-latency-us = <1000>;
        min-residency-us = <2000>;
    };
};

thermal-zones {
    cpu-thermal {
        ___ = <1000>;
        polling-delay-passive = <250>;

        thermal-sensors = <&tsensor 0>;

        trips {
            cpu_alert: cpu-alert {
                temperature = <75000>;
                hysteresis = <2000>;
                type = "___";
            };
        };
    };
};

static struct cpuidle_driver my_idle_driver = {
    .name = "my_idle",
    .owner = THIS_MODULE,
    .states = {
        {
            .name = "WFI",
            .desc = "ARM WFI",
            .exit_latency = 1,
            .target_residency = 1,
            .enter = my_enter_wfi,
        },
    },
    .state_count = 1,
};

static int __init my_idle_init(void)
{
    return ___(&my_idle_driver);
}

firmware {
    scmi {
        compatible = "arm,scmi";
        ___ = <&mailbox 0>;
        ___ = <&cpu_scp_shm>;

        scmi_perf: protocol@13 {
            reg = <0x13>;
        };
    };
};

static void handle_exception(void)
{
    unsigned long esr;
    unsigned int ec;

    asm volatile("mrs %0, ___" : "=r"(esr));
    ec = (esr >> ___) & 0x3F;

    switch (ec) {
    case 0x15: /* SVC from AArch64 */
        handle_svc();
        break;
    case 0x24: /* Data Abort from lower EL */
        handle_data_abort();
        break;
    }
}
